head.script:
//
(function(){
  try{
    var t = localStorage.getItem('theme');
    if(t === 'light'){ document.documentElement.classList.remove('dark'); }
    else { document.documentElement.classList.add('dark'); }
  }catch(e){ document.documentElement.classList.add('dark'); }
})();
//

//
tailwind.config = {
  darkMode: 'class',
  theme: {
    extend: {
      colors: {
        ink: {
          50:'#f7f7f8', 100:'#ededf0', 200:'#d9d9df', 300:'#b8b8c2',
          400:'#8e8e9c', 500:'#6b6b78', 600:'#52525b', 700:'#3f3f46',
          800:'#27272a', 900:'#18181b', 950:'#0b0b0d'
        }
      },
      fontFamily: {
        sans: ['Inter','ui-sans-serif','system-ui','sans-serif'],
        display: ['"Space Grotesk"','ui-sans-serif','sans-serif']
      }
    }
  }
};
//

head.b:skin:
:root { color-scheme: light dark; }
body { font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.font-display { font-family: "Space Grotesk", ui-sans-serif, sans-serif; }
/* Header transparan -> solid saat scroll */
[data-header]{ transition: background-color .3s ease, border-color .3s ease, backdrop-filter .3s ease; }
[data-header].is-scrolled{
  background-color: rgba(11,11,13,.7);
  backdrop-filter: blur(14px);
  border-bottom: 1px solid rgba(39,39,42,.8);
}
html:not(.dark) [data-header].is-scrolled{
  background-color: rgba(255,255,255,.75);
  border-bottom: 1px solid rgba(237,237,240,.9);
}
/* Reveal on scroll */
.reveal{ opacity:0; transform: translateY(16px); transition: opacity .6s ease, transform .6s ease; }
.reveal.is-visible{ opacity:1; transform:none; }
@media (prefers-reduced-motion: reduce){
  .reveal{ opacity:1 !important; transform:none !important; transition:none; }
  .animate-ping{ animation:none !important; }
}
/* Konten halaman (data:post.body) mewarisi gaya prose ringan */
.page-body :is(h1,h2,h3){ font-family:"Space Grotesk", sans-serif; }
/* Sembunyikan judul/footer post bawaan Blogger */
.page-body .post-footer, .page-body .post-title, .page-body .post-header{ display:none; }

/* Background ombak air hitam elegan (dark mode) */
.ocean-bg{ position:fixed; inset:0; z-index:0; overflow:hidden; opacity:0; transition:opacity .6s ease; pointer-events:none; }
.dark .ocean-bg{ opacity:1; background:linear-gradient(180deg,#0a1628 0%,#0b1d30 60%,#0d2438 100%); }
.ocean-bg svg{ position:absolute; bottom:0; left:0; width:200%; height:auto; }
.wave1{ animation:oceanDrift 22s linear infinite; opacity:.5; }
.wave2{ animation:oceanDrift 34s linear infinite reverse; opacity:.35; bottom:-10px; }
.wave3{ animation:oceanDrift 48s linear infinite; opacity:.22; bottom:-25px; }
@keyframes oceanDrift{ from{ transform:translateX(0); } to{ transform:translateX(-50%); } }
.ocean-bg::after{ content:''; position:absolute; inset:0; background:radial-gradient(ellipse at 50% 0%, transparent 35%, rgba(0,0,0,.6) 100%); }
@media (prefers-reduced-motion: reduce){ .wave1,.wave2,.wave3{ animation:none !important; } }

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//

body.script:
//
document.addEventListener('DOMContentLoaded', function(){
  var root = document.documentElement;

  function setIcons(){
    var dark = root.classList.contains('dark');
    document.querySelectorAll('[data-icon-sun]').forEach(function(el){ el.style.display = dark ? 'block' : 'none'; });
    document.querySelectorAll('[data-icon-moon]').forEach(function(el){ el.style.display = dark ? 'none' : 'block'; });
  }
  document.querySelectorAll('[data-theme-toggle]').forEach(function(b){
    b.addEventListener('click', function(){
      root.classList.toggle('dark');
      try{ localStorage.setItem('theme', root.classList.contains('dark') ? 'dark' : 'light'); }catch(e){}
      setIcons();
    });
  });
  setIcons();

  var mb = document.querySelector('[data-menu-toggle]');
  var mm = document.querySelector('[data-mobile-menu]');
  if(mb && mm){ mb.addEventListener('click', function(){ mm.classList.toggle('hidden'); }); }

  var hdr = document.querySelector('[data-header]');
  if(hdr){
    var onScroll = function(){
      if(window.scrollY > 16){ hdr.classList.add('is-scrolled'); }
      else { hdr.classList.remove('is-scrolled'); }
    };
    window.addEventListener('scroll', onScroll); onScroll();
  }

  // Highlight menu aktif
  var path = location.pathname;
  document.querySelectorAll('[data-nav]').forEach(function(a){
    var href = a.getAttribute('href');
    if((href === '/' && (path === '/' || path === '')) || (href !== '/' && path.indexOf(href) === 0)){
      a.classList.add('text-ink-950','dark:text-white','font-medium');
    }
  });

  // Reveal saat scroll
  var io = new IntersectionObserver(function(entries){
    entries.forEach(function(e){ if(e.isIntersecting){ e.target.classList.add('is-visible'); io.unobserve(e.target); } });
  }, { threshold: 0.1, rootMargin: '0px 0px -60px 0px' });
  document.querySelectorAll('.reveal').forEach(function(el){ io.observe(el); });
});
//

//
(function(){
  function revealInView(){
    var vh = window.innerHeight || document.documentElement.clientHeight;
    var els = document.querySelectorAll('.reveal');
    for(var i=0;i<els.length;i++){
      var r = els[i].getBoundingClientRect();
      if(r.top < vh + 80){ els[i].classList.add('is-visible'); }
    }
  }
  window.addEventListener('load', revealInView);
  setTimeout(revealInView, 1500);
})();
//

//
(function(){
  if(!document.getElementById('proyek-grid')) return;
  var Q='"', C='class', B='blogspot';
  var BLOG='https://muzadidil.'+B+'.com';

  function fmtDate(s){
    return new Date(s).toLocaleDateString('id-ID',{day:'numeric',month:'short',year:'numeric'});
  }
  function stripHtml(h){
    var d=document.createElement('div');
    d.innerHTML=h;
    return (d.textContent||d.innerText||'').replace(/s+/g,' ').trim();
  }
  function getThumb(e){
    var mt=e['media$thumbnail'];
    if(mt&&mt['$t']){
      return mt['$t'].replace('/s72-c/','/s600-c/').replace('/s72/','/s600/');
    }
    var h=((e.content||e.summary)||{})['$t']||'';
    var d=document.createElement('div');
    d.innerHTML=h;
    var img=d.querySelector('img');
    return img?img.src:null;
  }
  function getDesc(e){
    var h=((e.summary||e.content)||{})['$t']||'';
    var t=stripHtml(h);
    return t.length>110?t.substring(0,110)+'...':t;
  }
  function getUrl(e){
    for(var i=0,l=e.link||[];i<l.length;i++){if(l[i].rel==='alternate')return l[i].href;}
    return '#';
  }
  function getCat(e){
    return ((e.category||[{term:'Proyek'}])[0]).term;
  }

  function makeCard(e){
    var title=(e.title||{})['$t']||'Tanpa Judul';
    var url=getUrl(e);
    var thumb=getThumb(e);
    var desc=getDesc(e);
    var date=e.published?fmtDate(e.published['$t']):'';
    var cat=getCat(e);

    var a=document.createElement('a');
    a.href=url;
    a[C+'Name']='proyek-card';
    a.target='_blank';

    // Image
    if(thumb){
      var img=document.createElement('img');
      img[C+'Name']='proyek-card-img';
      img.src=thumb;
      img.alt=title;
      img.loading='lazy';
      img.onerror=function(){
        var ph=document.createElement('div');
        ph[C+'Name']='proyek-card-placeholder';
        ph.innerHTML='&#128247;';
        this.parentNode.replaceChild(ph,this);
      };
      a.appendChild(img);
    } else {
      var ph=document.createElement('div');
      ph[C+'Name']='proyek-card-placeholder';
      ph.innerHTML='&#128247;';
      a.appendChild(ph);
    }

    // Body
    var body=document.createElement('div');
    body[C+'Name']='proyek-card-body';

    var catEl=document.createElement('div');
    catEl[C+'Name']='proyek-card-cat';
    catEl.textContent=cat;
    body.appendChild(catEl);

    var titleEl=document.createElement('div');
    titleEl[C+'Name']='proyek-card-title';
    titleEl.textContent=title;
    body.appendChild(titleEl);

    var descEl=document.createElement('div');
    descEl[C+'Name']='proyek-card-desc';
    descEl.textContent=desc;
    body.appendChild(descEl);

    var dateEl=document.createElement('div');
    dateEl[C+'Name']='proyek-card-date';
    dateEl.textContent=date;
    body.appendChild(dateEl);

    a.appendChild(body);
    return a;
  }

  window.renderProyek=function(data){
    var grid=document.getElementById('proyek-grid');
    var countEl=document.getElementById('proyek-count');
    if(!grid) return;
    grid.innerHTML='';
    if(!data||!data.feed||!data.feed.entry){
      var emp=document.createElement('div');
      emp[C+'Name']='proyek-empty';
      emp.textContent='Belum ada proyek yang dipublikasikan.';
      grid.appendChild(emp);
      if(countEl) countEl.textContent='0 Proyek';
      return;
    }
    var entries=data.feed.entry;
    if(countEl) countEl.textContent=entries.length+' Proyek';
    for(var i=0;i<entries.length;i++){
      grid.appendChild(makeCard(entries[i]));
    }
  };

  var s=document.createElement('script');
  s.src=BLOG+'/feeds/posts/default/-/Proyek?alt=json&max-results=500&callback=renderProyek';
  s.onerror=function(){
    var g=document.getElementById('proyek-grid');
    if(g){
      g.innerHTML='';
      var e=document.createElement('div');
      e[C+'Name']='proyek-empty';
      e.textContent='Gagal memuat. Coba muat ulang halaman.';
      g.appendChild(e);
    }
  };
  document.body.appendChild(s);
})();
//
